import anthropic

client = anthropic.Anthropic()


def run_agent(task: str, max_steps: int = 50) -> str:
    """
    Run the perceive-decide-act loop until the model signals completion
    or max_steps is reached.
    """
    messages = []
    # Bootstrap with the first screenshot
    screenshot = capture_screenshot()
    messages.append({
        "role": "user",
        "content": [
            {
                "type": "tool_result",
                "tool_use_id": "initial",
                "content": [
                    {"type": "image",
                     "source": {"type": "base64",
                                "media_type": "image/png",
                                "data": screenshot}}
                ]
            },
            {"type": "text", "text": task}
        ]
    })

    for step in range(max_steps):
        response = client.beta.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=[{"type": "computer_20250124", "name": "computer",
                    "display_width_px": 1920, "display_height_px": 1080}],
            messages=messages,
            betas=["computer-use-2025-01-24"],
        )

        # Append assistant turn
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Model finished the task
            text_blocks = [b.text for b in response.content
                           if hasattr(b, "text")]
            return " ".join(text_blocks)

        # Collect all tool uses in this turn
        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            action = block.input
            execute_action(action)

            # After each action, capture a fresh screenshot
            new_screenshot = capture_screenshot()
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": [
                    {"type": "image",
                     "source": {"type": "base64",
                                "media_type": "image/png",
                                "data": new_screenshot}}
                ]
            })

        if not tool_results:
            break  # no tool calls and not end_turn — stop to avoid infinite loop

        messages.append({"role": "user", "content": tool_results})

    return "Max steps reached without completion."
